from langflow.custom import Component
from langflow.io import MessageTextInput, Output
from langflow.schema.message import Message

class UserDetailsParserComponent(Component):
    display_name = "User Details Parser"
    description = "Parses raw user details and detects portfolio category"
    icon = "user"

    inputs = [
        MessageTextInput(name="raw_input", display_name="Raw User Details"),
    ]
    outputs = [
        Output(display_name="Category", name="category", method="get_category"),
        Output(display_name="Raw Text", name="raw_text", method="get_raw_text"),
    ]

    CATEGORY_KEYWORDS = {
        "photography": ["photographer", "photography", "camera", "shoot", "lens"],
        "chef": ["chef", "cuisine", "restaurant", "recipe", "culinary"],
        "education": ["teacher", "professor", "student", "degree", "university"],
        "developer": ["developer", "engineer", "programming", "github", "software"],
        "artist": ["artist", "painting", "sculpture", "gallery"],
        "musician": ["musician", "singer", "composer", "album"],
        "fitness": ["trainer", "fitness", "coach", "gym"],
        "writer": ["writer", "author", "novel", "blog"],
        "designer": ["designer", "ux", "ui designer", "branding"],
        "doctor": ["doctor", "physician", "clinic", "medical"],
        "dancer": ["dancer", "choreographer", "bharatanatyam"],
    }

    def detect_category(self, text: str) -> str:
        text_lower = text.lower()
        scores = {c: sum(1 for kw in kws if kw in text_lower) for c, kws in self.CATEGORY_KEYWORDS.items()}
        best = max(scores, key=scores.get)
        return best if scores[best] > 0 else "general"

    def get_category(self) -> Message:
        return Message(text=self.detect_category(self.raw_input))

    def get_raw_text(self) -> Message:
        return Message(text=self.raw_input)

