    display_name = "HTML Portfolio Renderer"
    description = "Renders portfolio JSON into the Figma-Portfolio-style structure with a Gemini-style animated gradient background"
    icon = "code"

    inputs = [MessageTextInput(name="content_json", display_name="Portfolio JSON")]
    outputs = [Output(display_name="HTML Output", name="html_output", method="render")]

    def _clean_json(self, raw: str) -> str:
        raw = raw.strip()
        if raw.startswith("```"):
            raw = raw.strip("`")
            if raw.lower().startswith("json"):
                raw = raw[4:]
        return raw.strip()

    def _initials(self, name: str) -> str:
        parts = [p for p in name.split() if p]
        return "".join(p[0].upper() for p in parts[:2]) if parts else "P"

    def render(self) -> Message:
        raw = self._clean_json(self.content_json)
        try:
            data = json.loads(raw)
