            title = it.split(":")[0].strip() if ":" in it else it[:42]
            desc = it.split(":", 1)[1].strip() if ":" in it else it
            work_cards += f"""
            <div class="exp-card">
              <div class="exp-icon">{title[:2].upper()}</div>
              <div>
                <h3>{title}</h3>
                <p>{desc}</p>
                <a href="#contact" class="learn-more">LEARN MORE →</a>
