        contact = data.get("contact", {})
        contact_email = contact.get("email", "")
        contact_bits = [v for v in [contact.get("phone"), contact.get("location")] if v]
        links_html = "".join(
            f'<a class="social-link" href="{l}" target="_blank">{l.replace("https://","").replace("http://","")}</a>'
            for l in contact.get("links", [])
